func cashFlowAPIHref(vm CashFlowVM) string {
	values := url.Values{}
	if vm.Toolbar.Preset != "" {
		values.Set("period", vm.Toolbar.Preset)
	}
	if vm.From != "" {
		values.Set("from", vm.From)
	}
	if vm.To != "" {
		values.Set("to", vm.To)
	}
	encoded := values.Encode()
	if encoded == "" {
		return "/api/reports/cash-flow"
	}
	return "/api/reports/cash-flow?" + encoded
}

